const payload = $json.body ?? $json;
const task = payload.task ?? payload;
const taskInput = task.input ?? {};
const taskId = String(task.taskId ?? '').trim();
const callbackUrl = String(task.callbackUrl ?? '').trim();
const reviewUrl = String(task.reviewUrl ?? '').trim();
const supplierName = String(task.supplierName ?? '').trim();
if (!taskId) {
  throw new Error('Missing taskId.');
}
if (!callbackUrl) {
  throw new Error('Missing callbackUrl.');
}
if (!supplierName) {
  throw new Error('Missing supplierName.');
}
return [{ json: { event: payload.event ?? null, occurredAt: payload.occurredAt ?? null, taskId, callbackUrl, callbackSecret: typeof task.callbackSecret === 'string' ? task.callbackSecret : null, reviewUrl, supplierName, website: typeof task.website === 'string' ? task.website : null, orderNumber: typeof task.orderNumber === 'string' ? task.orderNumber : null, purchaseOrderId: typeof task.purchaseOrderId === 'string' ? task.purchaseOrderId : null, requiresApproval: task.requiresApproval !== false, input: taskInput, receivedAt: new Date().toISOString() } }];

const taskInput = $json.input ?? {};
const requestedLines = Array.isArray(taskInput.lines) ? taskInput.lines : [];
const steps = Array.isArray(taskInput.steps) ? taskInput.steps : [];
const evidenceChecklist = Array.isArray(taskInput.evidenceChecklist) ? taskInput.evidenceChecklist : [];
const runId = `n8n-web-order-${Date.now()}`;
const summary = `Website-order prep is ready for manager review for ${$json.supplierName}.`;
return [{ json: { ...$json, runId, callbackPayload: { taskId: $json.taskId, status: 'READY_FOR_REVIEW', summary, externalRunId: runId, externalUrl: $json.reviewUrl || $json.website || null, output: { provider: 'n8n', supplierName: $json.supplierName, website: $json.website, reviewUrl: $json.reviewUrl, orderNumber: $json.orderNumber, purchaseOrderId: $json.purchaseOrderId, requestedLines, steps, evidenceChecklist, approvalGate: taskInput.approvalGate ?? 'Final supplier checkout remains manager-approved in v1.', nextStep: $json.website ? 'Open the supplier portal, prepare the cart, capture totals, and stop before final checkout.' : 'Review the StockPilot task and enrich supplier portal details before checkout.', receivedAt: $json.receivedAt } }, responseBody: { accepted: true, message: `n8n accepted website-order prep for ${$json.supplierName}.`, runId, dispatchState: 'pending', reviewUrl: $json.reviewUrl || null, receivedAt: $json.receivedAt } } }];
